/*
 * Simple single-buffer firmware update for small firmware images.
 * Downloads entire binary to RAM first, then writes to flash.
 * Only suitable when enough heap is available.
 */
fw_err_t fw_update_simple(const char *url)
{
    fw_err_t err;
    uint32_t bytes_received = 0;

    if (!url || strlen(url) == 0 || strlen(url) >= MAX_URL_LEN) {
        log_error("Invalid URL");
        return FW_ERR_DOWNLOAD;
    }

    crc32_init_table();

    /* Allocate max firmware buffer */
    uint8_t *fw_buf = (uint8_t *)malloc(FLASH_OTA_PARTITION_SIZE);
    if (!fw_buf) {
        log_error("Failed to allocate firmware buffer");
        return FW_ERR_NOMEM;
    }

    log_info("Downloading firmware from: %s", url);

    if (http_download(url, fw_buf, FLASH_OTA_PARTITION_SIZE, &bytes_received) != 0) {
        log_error("HTTP download failed");
        free(fw_buf);
        return FW_ERR_DOWNLOAD;
    }

    log_info("Downloaded %u bytes", bytes_received);

    /* Parse and validate header */
    fw_header_t hdr;
    err = fw_parse_header(fw_buf, bytes_received, &hdr);
    if (err != FW_OK) {
        free(fw_buf);
        return err;
    }

    /* Verify payload CRC before flashing */
    uint8_t *payload = fw_buf + sizeof(fw_header_t);
    uint32_t payload_size = bytes_received - sizeof(fw_header_t);

    if (payload_size < hdr.size) {
        log_error("Incomplete payload: got %u, expected %u", payload_size, hdr.size);
        free(fw_buf);
        return FW_ERR_DOWNLOAD;
    }

    uint32_t computed_crc = crc32_compute(payload, hdr.size);
    if (computed_crc != hdr.crc32) {
        log_error("CRC mismatch: expected 0x%08X, got 0x%08X", hdr.crc32, computed_crc);
        free(fw_buf);
        return FW_ERR_VERIFY;
    }

    /* Erase flash */
    log_info("Erasing flash...");
    err = flash_erase_region(FLASH_OTA_PARTITION_ADDR, bytes_received);
    if (err != FW_OK) {
        free(fw_buf);
        return err;
    }

    /* Write to flash in sector-sized chunks */
    log_info("Writing firmware to flash...");
    uint32_t offset = 0;
    while (offset < bytes_received) {
        watchdog_feed();
        uint32_t chunk = bytes_received - offset;
        if (chunk > FLASH_SECTOR_SIZE)
            chunk = FLASH_SECTOR_SIZE;

        err = flash_write_aligned(FLASH_OTA_PARTITION_ADDR + offset, fw_buf + offset, chunk);
        if (err != FW_OK) {
            free(fw_buf);
            return err;
        }
        offset += chunk;
    }

    free(fw_buf);

    /* Final flash verification */
    log_info("Verifying flash...");
    err = flash_verify_region(FLASH_OTA_PARTITION_ADDR + sizeof(fw_header_t),
                              hdr.size, hdr.crc32);
    if (err != FW_OK)
        return err;

    log_info("Update successful. Rebooting...");
    for (volatile int i = 0; i < 100000; i++) { }
    system_reboot();

    return FW_OK;
}

